// ────────────────────────────────────────────────────────────
// LOOKUP — by ShopItem id
// ────────────────────────────────────────────────────────────

const SHOP_SVG_BY_ID: Record<string, React.FC<IconProps>> = {
  // boosts
  'boost-xp-2x-1h': BoostXP,
  'boost-coins-2x-1h': BoostCoins,
  'boost-mega-1h': BoostMega,
  'boost-weekend': BoostWeekend,
  // shields
  'streak-shield-week': ShieldWeek,
  'streak-shield-month': ShieldMonth,
  'streak-revival-elite': ShieldElite,
  // hearts
  'heart-refill-1': HeartRefill1,
  'heart-refill-full': HeartRefillFull,
  // hints
  'hint-single': HintSingle,
  'hint-bundle': HintBundle,
  // freezes
  'streak-freeze': FreezeSingle,
  'streak-freeze-bundle': FreezeBundle,
};

/**
 * Returns the SVG component for a shop item id, or null if no SVG is available
 * (in which case the caller should fall back to the item's Lottie or emoji).
 */
export function getShopSvgIcon(itemId: string): React.FC<IconProps> | null {
  return SHOP_SVG_BY_ID[itemId] ?? null;
}
